create table dirkspzm32.isi_security_cfg (
    sid             varchar2(2 char) not null enable,
    firma_nr        number(6, 0) not null enable,
    security_cfg_id number(*, 0) not null enable,
    group_id        number(*, 0) not null enable,
    module_name     varchar2(40 char) not null enable,
    kategorie       varchar2(40 char) not null enable,
    kategorie_ix    varchar2(40 char),
    parameter_name  varchar2(40 char) not null enable,
    parameter_wert  varchar2(4000 char),
    parameter_typ   varchar2(15 char) not null enable
);

alter table dirkspzm32.isi_security_cfg
    add constraint pk_isi_security_cfg
        primary key ( sid,
                      firma_nr,
                      security_cfg_id )
            using index enable;


